/**
 * Generate Clado firewall config.
 *
 * Data source: https://clado.ai
 *
 * Clado authenticates with a Bearer token on `https://search.clado.ai/...`.
 */

import { writeOutput } from "./codegen";

const DOCS_URL = "https://clado.ai";
const PLACEHOLDER_VALUE = "CoffeeSafeLocalCoffeeSafeLocalCoffeeSafe";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Clado API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:clado",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const cladoFirewall = {",
    '  name: "clado",',
    '  description: "Clado API",',
    "  placeholders: {",
    `    CLADO_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://search.clado.ai",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.CLADO_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Clado firewall config...");
  const ts = generateTypeScript();
  writeOutput("clado", ts, import.meta.dirname);
}
